#[derive(Debug, Error)]
pub enum Error {
    #[error("Database error: {0}")]
    Db(#[from] DbError),
    #[error("Coin Selection error: {0}")]
    CoinSelection(#[from] BdkCoinselectionError),
    #[error("Pbst error: {0}")]
    Pbst(#[from] PsbtError),
    // Two distinct PSBT related errors one from bdk and one from rust bitcoin
    #[error("Pbst error: {0}")]
    PbstError(#[from] bitcoin::psbt::Error),
    #[error("Invalid resulting transaction")]
    InvaildResultingTx,
    #[error("Invalid tx request, dkg has not been completed")]
    InvalidTxRequestMissingDKG,
    #[error("Failed to sign pbst")]
    FailedToSignPbst,
    #[error("PSBT finalization failed : {0:?}")]
    PbstFinalizationFailed(Vec<PsbtError>),
    #[error("Invalid Frost peer id")]
    InvalidFrostPeerId,
    #[error("Invalid round1 Dkg payload: {0}")]
    InvalidRoundDkgPayload(#[from] frost::Error),
    #[error("Invalid Dkg serialization format: {0}")]
    InvalidRoundDkgSerializationFormat(#[from] serde_json::Error),
    #[error("Invalid round 2 Dkg payload, missing our package")]
    InvalidRound2DkgPayloadMissingPackage,
    #[error("Invalid round2 Signing payload")]
    InvalidRound2SigningPayload(),
    #[error("Already have quorum of partial signatures")]
    AlreadyHaveQuorumOfPartialSignatures(),
    #[error("Already have a key package")]
    AlreadyHaveKeyPackage,
    #[error("Missing key package, need to perform DKG first")]
    MissingKeyPackage,
    #[error("Missing signing package")]
    MissingSigningPackage,
    #[error("Not enough signers have provided round1 commitments to create signing package")]
    NotEnoughSigners,
    #[error("Missing round 1 signing nonce")]
    MissingRound1SigningNonce,
    #[error("Missing round 2 signing package")]
    MissingRound2SigningPackage,
    #[error("Invalid signing package {0}")]
    InvalidSigningPackage(&'static str),
    #[error("Missing round 1 dkg package")]
    MissingRound1DkgPackage,
    #[error("io error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Failed to calculate sighash")]
    FailedToCalculateSighash,
    #[error("Invalid input index")]
    InvalidInputIndex,
    #[error("Bad eth address {0}")]
    BadEthAddress(&'static str),
    #[error("Signing session already in progress")]
    AlreadyInSigningSession,
    #[error("Invalid signing session id")]
    InvalidSigningSessionId,
    #[error("Failed to derive secp public key {0}")]
    FailedToDeriveSecpPublicKey(#[from] crate::util::VerifyingKeyExtError),
}

struct App {
    db: database::Db,
    network: bitcoin::Network,
    /// This lock is taken when we're making a tx so that we don't accidentally
    /// spend the same operations twice.
    tx_lock: Arc<Mutex<()>>,
    identifier: frost::Identifier,
    // TODO (armins) check that you have threshold amount of signers when accepting dkg packages
    max_signers: u16,
    min_signers: u16,
    frost_round1_dkg:
        Option<(frost::keys::dkg::round1::SecretPackage, frost::keys::dkg::round1::Package)>,
    frost_round2_dkg: Arc<Mutex<Option<frost::keys::dkg::round2::SecretPackage>>>,
    /// The signing nonces for the current signing session
    /// We will replace this value in the case of a new signing session
    frost_round1_signing_nonces: Arc<Mutex<Option<Vec<frost::round1::SigningNonces>>>>,
}

impl App {
    fn add_pegin(&self, utxo: &Utxo) -> Result<(), Error> {
        if self.db.store_utxo(&utxo).map_err(Error::Db)? {
            self.db.flush().map_err(Error::Db)?;
            debug!("Stored utxo {}", utxo.outpoint);
        } else {
            warn!("Duplicate utxo {}", utxo.outpoint);
        }
        Ok(())
    }
}

macro_rules! badarg {
    ($($arg:tt)*) => {{
        tonic::Status::invalid_argument(format!($($arg)*))
    }};
}

macro_rules! already_exists {
    ($($arg:tt)*) => {{
        tonic::Status::already_exists(format!($($arg)*))
    }};
}

macro_rules! internal {
    ($($arg:tt)*) => {{
        tonic::Status::internal(format!($($arg)*))
    }};
}

trait ToStatus<T> {
    fn to_status(self) -> Result<T, tonic::Status>;
}

impl<T> ToStatus<T> for Result<T, Error> {
    fn to_status(self) -> Result<T, tonic::Status> {
        self.map_err(|e| tonic::Status::internal(format!("internal error: {}", e)))
    }
}

#[tonic::async_trait]
impl rpc::BtcServer for App {
    // Saves peg'd in UTXO
    async fn notify_pegin(
        &self,
        req: tonic::Request<rpc::NotifyPeginRequest>,
    ) -> Result<tonic::Response<rpc::Empty>, tonic::Status> {
        let req = req.into_inner();
        let txid = req.utxo_txid.parse().map_err(|e| badarg!("bad txid: {}", e))?;
        let outpoint = OutPoint::new(txid, req.utxo_vout);

        let eth_addr = parse_eth_address(req.eth_address).map_err(|e| {
            error!("Failed to parse eth address: {}", e);
            badarg!("Failed to parse eth address: {}", e)
        })?;
        let utxo = Utxo {
            outpoint,
            output: btcencode::deserialize(&req.output)
                .map_err(|e| badarg!("bad txout format: {}", e))?,
            eth_address: Some(eth_addr),
        };

        self.add_pegin(&utxo).to_status()?;

        Ok(tonic::Response::new(rpc::Empty {}))
    }

    async fn finalize_signing(
        &self,
        req: tonic::Request<rpc::FinalizeSigningRequest>,
    ) -> Result<tonic::Response<rpc::FinalizeSigningResponse>, tonic::Status> {
        let req = req.into_inner();
        let mut psbt = Psbt::deserialize(&req.psbt.as_slice()).map_err(|e| {
            error!("Failed to deserialize psbt: {}", e);
            internal!("Failed to deserialize psbt: {}", e)
        })?;
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;

        let tx = self.finalize_signing(&SECP, &mut psbt, &signing_session_id).map_err(|e| {
            error!("Failed to finalize signing: {}", e);
            internal!("Failed to finalize signing: {}", e)
        })?;

        let res = tonic::Response::new(rpc::FinalizeSigningResponse {
            transaction: bitcoin::consensus::encode::serialize(&tx),
        });
        Ok(res)
    }

    async fn get_to_sign_package(
        &self,
        req: tonic::Request<rpc::ToSignRequest>,
    ) -> Result<tonic::Response<rpc::SignPayload>, tonic::Status> {
        let req = req.into_inner();
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;

        let fee_rate =
            FeeRate::from_sat_per_vb(req.fee_rate as u64).ok_or(internal!("overflowed value"))?;

        let outputs_result: Result<Vec<TxOut>, tonic::Status> = req
            .outputs
            .into_iter()
            .map(|o| {
                let script_pubkey_result = bitcoin::Address::from_str(&o.address)
                    .map_err(|e| internal!("invalid address: {}", e))?
                    .assume_checked()
                    .script_pubkey();

                Ok(TxOut { script_pubkey: script_pubkey_result, value: o.value })
            })
            .collect();
        let outputs = outputs_result?;

        let (to_sign, psbt) =
            self.get_to_sign(outputs, fee_rate, &signing_session_id).map_err(|e| {
                error!("Failed to get to sign: {}", e);
                internal!("Failed to get to sign: {}", e)
            })?;

        let psbt_bytes = hex::decode(psbt.serialize_hex()).map_err(|e| {
            error!("Failed to serialize psbt: {}", e);
            internal!("Failed to serialize psbt: {}", e)
        })?;
        let res = tonic::Response::new(rpc::SignPayload {
            payload: serde_json::to_vec(&to_sign)
                .map_err(|e| {
                    error!("Failed to serialize signing package: {}", e);
                    internal!("Failed to serialize signing package: {}", e)
                })?
                .to_vec(),
            psbt: psbt_bytes,
            signing_session_id: signing_session_id.to_vec(),
        });
        Ok(res)
    }

    async fn new_round1_signing_package(
        &self,
        req: tonic::Request<rpc::Round1SigningPackage>,
    ) -> Result<tonic::Response<rpc::Empty>, tonic::Status> {
        let req = req.into_inner();
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;
        let frost_id = util::deserialize_frost_peer_id(req.identifier).map_err(|e| {
            error!("Failed to parse frost peer id: {}", e);
            badarg!("Failed to parse frost peer id: {}", e)
        })?;
        let signing_commitments = serde_json::from_slice(&req.payload.as_slice()).map_err(|e| {
            error!("Failed to deserialize signing commitments: {}", e);
            badarg!("Failed to deserialize signing commitments: {}", e)
        })?;

        self.add_round1_signing(&signing_session_id, frost_id, signing_commitments).map_err(
            |e| {
                error!("Failed to add round1 signing: {}", e);
                badarg!("Failed to add round1 signing")
            },
        )?;

        Ok(tonic::Response::new(rpc::Empty {}))
    }

    async fn new_round2_signing_package(
        &self,
        req: tonic::Request<rpc::Round2SigningPackage>,
    ) -> Result<tonic::Response<rpc::Empty>, tonic::Status> {
        let req = req.into_inner();
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;
        let frost_id = util::deserialize_frost_peer_id(req.identifier).map_err(|e| {
            error!("Failed to parse frost peer id: {}", e);
            badarg!("Failed to parse frost peer id: {}", e)
        })?;

        let signature_shares: Vec<frost::round2::SignatureShare> =
            serde_json::from_slice(&req.payload.as_slice()).map_err(|e| {
                error!("Failed to deserialize signature share: {}", e);
                badarg!("Failed to deserialize signature share: {}", e)
            })?;

        self.add_round2_signing(&signing_session_id, frost_id, signature_shares).map_err(|e| {
            error!("Failed to add round2 signing: {}", e);
            badarg!("Failed to add round2 signing")
        })?;

        Ok(tonic::Response::new(rpc::Empty {}))
    }

    async fn get_public_key(
        &self,
        req: tonic::Request<rpc::GetPublicKeyRequest>,
    ) -> Result<tonic::Response<rpc::GetPublicKeyResponse>, tonic::Status> {
        let req = req.into_inner();
        let eth_address = parse_eth_address(req.eth_address).map_err(|e| {
            error!("Failed to parse eth address: {}", e);
            badarg!("Failed to parse eth address: {}", e)
        })?;
        let pk = self.get_public_key(&eth_address).map_err(|e| {
            error!("Failed to get public key: {}", e);
            internal!("Failed to get public key: {}", e)
        })?;
        let hex = hex::encode(pk.serialize());
        return Ok(tonic::Response::new(rpc::GetPublicKeyResponse { publickey: hex }));
    }

    async fn new_round2_dkg_package(
        &self,
        req: tonic::Request<rpc::DkgPayload>,
    ) -> Result<tonic::Response<rpc::Empty>, tonic::Status> {
        self.add_round2_dkg(req.into_inner()).map_err(|e| {
            error!("Failed to add round2 dkg: {}", e);
            badarg!("Failed to add round2 dkg")
        })?;
        Ok(tonic::Response::new(rpc::Empty {}))
    }

    async fn get_round2_dkg_package(
        &self,
        _req: tonic::Request<rpc::Empty>,
    ) -> Result<tonic::Response<rpc::DkgPayload>, tonic::Status> {
        let round2_packages = self.get_round2_dkg().map_err(|e| {
            error!("Failed to get round2 dkg package: {}", e);
            internal!("Failed to get round2 dkg package: {}", e)
        })?;
        let json = serde_json::to_string(&round2_packages).unwrap();
        let res = rpc::DkgPayload {
            identifier: self.identifier.serialize().to_vec(),
            payload: json.as_bytes().to_vec(),
        };
        Ok(tonic::Response::new(res))
    }

    async fn new_round1_dkg_package(
        &self,
        req: tonic::Request<rpc::DkgPayload>,
    ) -> Result<tonic::Response<rpc::Empty>, tonic::Status> {
        self.add_round1_dkg(req.into_inner()).map_err(|e| {
            error!("Failed to add round1 dkg: {}", e);
            internal!("Failed to add round1 dkg")
        })?;
        Ok(tonic::Response::new(rpc::Empty {}))
    }

    async fn get_round1_dkg_package(
        &self,
        _req: tonic::Request<rpc::Empty>,
    ) -> Result<tonic::Response<rpc::DkgPayload>, tonic::Status> {
        let round1_dkg_package = self.get_round1_dkg().map_err(|e| {
            error!("Failed to get round1 dkg package: {}", e);
            internal!("Failed to get round1 dkg package: {}", e)
        })?;
        let res = rpc::DkgPayload {
            identifier: self.identifier.serialize().to_vec(),
            payload: round1_dkg_package
                .serialize()
                .map_err(|e| {
                    error!("Failed to serialize round1 dkg package: {}", e);
                    internal!("Failed to serialize round1 dkg package: {}", e)
                })?
                .to_vec(),
        };

        Ok(tonic::Response::new(res))
    }

    /// Endpoint responds with a nonce commitments for a ONE particular signings session
    async fn get_round1_signing_package(
        &self,
        req: tonic::Request<rpc::Round1SigningPackageRequest>,
    ) -> Result<tonic::Response<rpc::Round1SigningPackage>, tonic::Status> {
        let req = req.into_inner();
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;
        let signing_commitments = self
            .get_round1_signing_package(req.number_of_inputs, &signing_session_id)
            .map_err(|e| {
                error!("Failed to get round1 signing package: {}", e);
                internal!("Failed to get round1 signing package: {}", e)
            })?;
        let signings_commitments_serialized =
            serde_json::to_vec(&signing_commitments).map_err(|e| {
                error!("Failed to serialize round1 signing package: {}", e);
                internal!("Failed to serialize round1 signing package: {}", e)
            })?;

        let res = rpc::Round1SigningPackage {
            identifier: self.identifier.serialize().to_vec(),
            payload: signings_commitments_serialized,
            signing_session_id: signing_session_id.to_vec(),
        };

        Ok(tonic::Response::new(res))
    }

    async fn get_round2_signing_package(
        &self,
        req: tonic::Request<rpc::SignPayload>,
    ) -> Result<tonic::Response<rpc::Round2SigningPackage>, tonic::Status> {
        let req = req.into_inner();
        let signing_session_id =
            util::parse_signing_session_id(&req.signing_session_id).map_err(|e| {
                error!("Failed to parse signing session id: {}", e);
                badarg!("Failed to parse signing session id: {}", e)
            })?;
        let mut signing_packages =
            serde_json::from_slice(&req.payload.as_slice()).map_err(|e| {
                error!("Failed to deserialize signing package: {}", e);
                badarg!("Failed to deserialize signing package: {}", e)
            })?;
        let psbt = Psbt::deserialize(req.psbt.as_slice()).map_err(|e| {
            error!("Failed to deserialize psbt: {}", e);
            internal!("Failed to deserialize psbt: {}", e)
        })?;
        let partial_signature =
            self.get_round2_signing_package(&mut signing_packages, &psbt).map_err(|e| {
                error!("Failed to get round2 signing package: {}", e);
                internal!("Failed to get round2 signing package: {}", e)
            })?;
        let psbt_bytes = hex::decode(psbt.serialize_hex()).map_err(|e| {
            error!("Failed to serialize psbt: {}", e);
            internal!("Failed to serialize psbt: {}", e)
        })?;

        // TODO (armins) Should we add partial sig to psbt
        let partial_sigs_serialized = serde_json::to_vec(&partial_signature).map_err(|e| {
            error!("Failed to serialize partial signature: {}", e);
            internal!("Failed to serialize partial signature: {}", e)
        })?;
        let res = rpc::Round2SigningPackage {
            identifier: self.identifier.serialize().to_vec(),
            payload: partial_sigs_serialized,
            psbt: psbt_bytes,
            signing_session_id: signing_session_id.to_vec(),
        };

        Ok(tonic::Response::new(res))
    }
}

#[derive(Parser)]
struct Config {
    /// The path to the database.
    #[arg(long)]
    db: PathBuf,
    /// The bitcoin network to operate on.
    #[arg(long)]
    network: bitcoin::Network,
    /// Frost participant identifier
    #[arg(long)]
    identifier: u16,
    #[arg(long)]
    address: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::builder()
        .filter_level(log::LevelFilter::Trace)
        .filter_module("sled::", log::LevelFilter::Info)
        .init();
    let config = Config::parse();
    let db = database::Db::open(&config.db).expect("failed to open db");

    let frost_identifier = frost::Identifier::derive(config.identifier.to_le_bytes().as_slice())
        .expect("valid identifier");
    info!("Frost identifier: {:?}", frost_identifier);

    let min_signers = 2;
    let max_signers = 3;

    let mut round1_dkg = None;
    if db.get_public_key_package().expect("failed to get public key package").is_none() {
        let rng = thread_rng();
        round1_dkg = Some(
            frost::keys::dkg::part1(frost_identifier.clone(), max_signers, min_signers, rng)
                .map_err(|e| internal!("Failed to generate round 1 dkg: {:?}", e))?,
        );
        info!("Successfully generated round 1 dkg: {:?}", round1_dkg);
    }

    let app = App {
        db,
        network: config.network,
        tx_lock: Arc::new(Mutex::new(())),
        identifier: frost_identifier,
        max_signers,
        min_signers,
        frost_round1_dkg: round1_dkg,
        frost_round2_dkg: Arc::new(Mutex::new(None)),
        frost_round1_signing_nonces: Arc::new(Mutex::new(None)),
    };
    let addr = config.address.parse().context("Unparsable address")?;
    info!("SignerServer starting on: {}...", addr);

    let server = rpc::BtcServerServer::new(app);
    tonic::transport::Server::builder().add_service(server).serve(addr).await?;

    info!("Server shutting down");
    Ok(())
}
